let activeEffect = null;

function reactive(target) {
  const deps = new Map();
  return new Proxy(target, {
    get(obj, prop) {
      if (activeEffect) {
        if (!deps.has(prop)) deps.set(prop, new Set());
        deps.get(prop).add(activeEffect);
      }
      return obj[prop];
    },
    set(obj, prop, value) {
      obj[prop] = value;
      const effects = deps.get(prop);
      if (effects) effects.forEach(fn => fn());
      return true;
    }
  });
}

function effect(fn) {
  activeEffect = fn;
  fn();
  activeEffect = null;
}

