class AsyncDisposableStack {
  #resources = [];
  #disposed = false;

  use(resource) {
    if (this.#disposed) throw new Error('Stack already disposed');
    if (resource[Symbol.asyncDispose]) {
      this.#resources.push(() => resource[Symbol.asyncDispose]());
    } else if (resource[Symbol.dispose]) {
      this.#resources.push(() => resource[Symbol.dispose]());
    }
    return resource;
  }

  defer(fn) {
    if (this.#disposed) throw new Error('Stack already disposed');
    this.#resources.push(fn);
  }

  async [Symbol.asyncDispose]() {
    if (this.#disposed) return;
    this.#disposed = true;
    const errors = [];
    // Dispose in LIFO order
    for (const cleanup of this.#resources.reverse()) {
      try { await cleanup(); } catch (e) { errors.push(e); }
    }
    if (errors.length === 1) throw errors[0];
    if (errors.length > 1) throw new AggregateError(errors);
  }
}

function lazy(factory) {
  let computed = false;
  let value;
  let error;
  let failed = false;

  return {
    get value() {
      if (failed) throw error;
      if (!computed) {
        try {
          value = factory();
          computed = true;
        } catch (e) {
          error = e;
          failed = true;
          throw e;
        }
      }
      return value;
    },
    get isEvaluated() { return computed; },
    reset() { computed = false; failed = false; value = undefined; error = undefined; }
  };
}

