class CancelablePromise {
  #canceled = false;
  #promise;
  #reject;

  constructor(executor) {
    this.#promise = new Promise((resolve, reject) => {
      this.#reject = reject;
      executor(
        (value) => { if (!this.#canceled) resolve(value); },
        (reason) => { if (!this.#canceled) reject(reason); }
      );
    });
  }

  cancel(reason = 'Canceled') {
    this.#canceled = true;
    this.#reject(new DOMException(reason, 'AbortError'));
  }

  get isCanceled() { return this.#canceled; }
  then(onFulfilled, onRejected) { return this.#promise.then(onFulfilled, onRejected); }
  catch(onRejected) { return this.#promise.catch(onRejected); }
  finally(onFinally) { return this.#promise.finally(onFinally); }
}

class EventEmitter {
  #listeners = new Map();

  on(event, fn) {
    if (!this.#listeners.has(event)) this.#listeners.set(event, []);
    this.#listeners.get(event).push({ fn, once: false });
    return () => this.off(event, fn);
  }

  once(event, fn) {
    if (!this.#listeners.has(event)) this.#listeners.set(event, []);
    this.#listeners.get(event).push({ fn, once: true });
  }

  off(event, fn) {
    const list = this.#listeners.get(event);
    if (list) this.#listeners.set(event, list.filter(l => l.fn !== fn));
  }

  emit(event, ...args) {
    const matched = [];
    for (const [key, listeners] of this.#listeners) {
      if (key === event || key === '*') matched.push(...listeners);
    }
    const remaining = [];
    for (const listener of matched) {
      listener.fn(...args);
      if (!listener.once) remaining.push(listener);
    }
    // Remove once listeners
    for (const [key, listeners] of this.#listeners) {
      this.#listeners.set(key, listeners.filter(l => !l.once || !matched.includes(l)));
    }
  }
}

class Semaphore {
  #permits;
  #queue = [];

  constructor(permits = 1) {
    this.#permits = permits;
  }

  async acquire() {
    if (this.#permits > 0) {
      this.#permits--;
      return;
    }
    return new Promise(resolve => this.#queue.push(resolve));
  }

  release() {
    if (this.#queue.length > 0) {
      const next = this.#queue.shift();
      next();
    } else {
      this.#permits++;
    }
  }

  async run(fn) {
    await this.acquire();
    try {
      return await fn();
    } finally {
      this.release();
    }
  }
}

