function pipe(...fns) {
  return function(input) {
    return fns.reduce(
      (acc, fn) => acc instanceof Promise ? acc.then(fn) : {
        result: (() => { try { return fn(acc); } catch(e) { return Promise.reject(e); } })()
      }.result,
      input
    );
  };
}

// Simpler alternative:
function pipeAsync(...fns) {
  return async function(input) {
    let result = input;
    for (const fn of fns) {
      result = await fn(result);
    }
    return result;
  };
}

